CREATE OR REPLACE FUNCTION fpa_lon_bal_atdate_by_lon_grp (as_memno char,adt_date timestamp(0),as_group_lon char) RETURNS bigint AS $body$
DECLARE

  ldc_number bigint;

BEGIN
  select sum(pka_com_function.fp_lon_get_balance_atdate(sc_lon_m_contract.loan_contract_no,to_date(adt_date,'dd/mm/yyyy')))
  into STRICT   ldc_number
  from   sc_lon_m_contract
      ,  sc_lon_m_rule
  where (sc_lon_m_contract.membership_no = as_memno)
  and (sc_lon_m_rule.loan_group_code = as_group_lon)
  and (sc_lon_m_rule.loan_type = sc_lon_m_contract.loan_type);

return coalesce(ldc_number,0);

exception when others then CALL spa_dberror('FPA_LON_BAL_ATDATE_BY_LON_GRP');return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
